CREATE TABLE `inventory_records` (
  `id` int NOT NULL AUTO_INCREMENT,
  `session_id` int NOT NULL,
  `asset_id` int NOT NULL,
  `expected_quantity` int DEFAULT '1',
  `actual_quantity` int DEFAULT '0',
  `actual_location_id` int DEFAULT NULL,
  `status` varchar(30) NOT NULL DEFAULT 'pending_check',
  `notes` text,
  `checked_by` int DEFAULT NULL,
  `checked_at` timestamp NULL DEFAULT NULL,
  `created_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`),
  UNIQUE KEY `unique_session_asset` (`session_id`,`asset_id`),
  KEY `asset_id` (`asset_id`),
  KEY `checked_by` (`checked_by`),
  CONSTRAINT `inventory_records_ibfk_1` FOREIGN KEY (`session_id`) REFERENCES `inventory_sessions` (`id`) ON DELETE CASCADE,
  CONSTRAINT `inventory_records_ibfk_2` FOREIGN KEY (`asset_id`) REFERENCES `assets` (`id`) ON DELETE CASCADE,
  CONSTRAINT `inventory_records_ibfk_3` FOREIGN KEY (`checked_by`) REFERENCES `users` (`id`) ON DELETE SET NULL
